process_chain.block:

starts-with $REQ.authToken "Bearer " || error --from lib "PC-TPL-AUTH-0001";

rewrite $REQ.path "/legacy/*" "/v2/*" || echo "skip_rewrite";

match $REQ.path "/v2/order/*" && return --from lib "upstream_order";
match $REQ.path "/v2/user/*" && return --from lib "upstream_user";

return --from lib "upstream_fallback";
